         (SELECT MIN(id) FROM departments) AS did
  FROM DUAL
) src ON (TRIM(s.name) = TRIM(src.n))
WHEN NOT MATCHED THEN INSERT (department_id, name, description)
  VALUES (src.did, src.n, 'تم الإنشاء من بيانات المهن');
MERGE INTO specializations s USING (
  SELECT 'فني حفر آبار' AS n,
         (SELECT MIN(id) FROM departments) AS did
  FROM DUAL
) src ON (TRIM(s.name) = TRIM(src.n))
WHEN NOT MATCHED THEN INSERT (department_id, name, description)
  VALUES (src.did, src.n, 'تم الإنشاء من بيانات المهن');
