-- 4. Subjects (linked to specialization + profession text column)
MERGE INTO subjects s USING (
  SELECT 'لغة انجليزية' AS n,
         'البرادة العامة' AS prof,
         50 AS mx,
         25 AS pm,
         1 AS dord,
         (SELECT MIN(id) FROM specializations WHERE TRIM(name) = TRIM('البرادة العامة')) AS specid
  FROM DUAL
) src ON (TRIM(s.name) = TRIM(src.n) AND TRIM(s.profession) = TRIM(src.prof))
WHEN NOT MATCHED THEN INSERT
  (specialization_id, profession, name, type, pass_mark, max_mark, display_order)
VALUES (src.specid, src.prof, src.n, 'نظري', src.pm, src.mx, src.dord);
